#include <stdio.h>
int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    int arr[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }
    int max_len = 0;
    for (int i = 0; i < N; i++) {
        int len = 1;
        for (int j = i + 1; j < N; j++) {
            if (arr[j] - arr[j - 1] == 1) {
                len++;
            } else {
                break;
            }
        }
        if (max_len < len) {
            max_len = len;
        }
    }
    printf("%d\n", max_len);
    for (int i = 0; i < M; i++) {
        int X, Y;
        scanf("%d %d", &X, &Y);
        arr[X - 1] = Y;
        max_len = 0;
        for (int j = 0; j < N; j++) {
            int len = 1;
            for (int k = j + 1; k < N; k++) {
                if (arr[k] - arr[k - 1] == 1) {
                    len++;
                } else {
                    break;
                }
            }
            if (max_len < len) {
                max_len = len;
            }
        }
        printf("%d\n", max_len);
    }
    return 0;
}

