import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int M = sc.nextInt();
        int[] arr = new int[N];
        for (int i = 0; i < N; i++) {
            arr[i] = sc.nextInt();
        }
        int max_len = 0;
        for (int i = 0; i < N; i++) {
            int len = 1;
            for (int j = i + 1; j < N; j++) {
                if (arr[j] - arr[j - 1] == 1) {
                    len++;
                } else {
                    break;
                }
            }
            max_len = Math.max(max_len, len);
        }
        System.out.println(max_len);
        for (int i = 0; i < M; i++) {
            int X = sc.nextInt();
            int Y = sc.nextInt();
            arr[X - 1] = Y;
            max_len = 0;
            for (int j = 0; j < N; j++) {
                int len = 1;
                for (int k = j + 1; k < N; k++) {
                    if (arr[k] - arr[k - 1] == 1) {
                        len++;
                    } else {
                        break;
                    }
                }
                max_len = Math.max(max_len, len);
            }
            System.out.println(max_len);
        }
    }
}

